UserController.java

package com.example.demo.controller;

import com.example.demo.dto.*;
import com.example.demo.projection.UserAddressProjection;
import com.example.demo.service.UserService;
import jakarta.validation.Valid;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/users")
public class UserController {

    private final UserService userService;

    public UserController(UserService userService) {
        this.userService = userService;
    }

    @PostMapping
    public UserSummaryResponse createUser(@Valid @RequestBody CreateUserRequest request) {
        return userService.createUser(request);
    }

    @GetMapping("/{id}")
    public UserDetailResponse getUserDetail(@PathVariable Long id) {
        return userService.getUserDetail(id);
    }

    @GetMapping("/{id}/projection")
    public UserAddressProjection getProjectedUser(@PathVariable Long id) {
        return userService.getProjectedUser(id);
    }

    @PutMapping("/{id}")
    public UserDetailResponse updateUser(@PathVariable Long id,
                                         @Valid @RequestBody UpdateUserRequest request) {
        return userService.updateUser(id, request);
    }

    @PutMapping("/{id}/address")
    public UserDetailResponse upsertAddress(@PathVariable Long id,
                                            @Valid @RequestBody UpsertAddressRequest request) {
        return userService.upsertAddress(id, request);
    }

    @DeleteMapping("/{id}")
    public void deleteUser(@PathVariable Long id) {
        userService.deleteUser(id);
    }
}


